const activities = $json.activities?.activities || $json.activities || [];
const baseDate = new Date(($json.gantt?.project_start || new Date().toISOString().split('T')[0]));
function addDays(date, days) {
  const d = new Date(date);
  d.setDate(d.getDate() + days);
  return d;
}
function toISODate(date) {
  return date.toISOString().split('T')[0];
}
let current = new Date(baseDate);
const tasks = activities.map(a => {
  const start = new Date(current);
  const end = addDays(start, Math.max(1, a.estimated_days || 1));
  current = addDays(end, 1);
  return {
    id: a.activity_id,
    name: a.title,
    start: toISODate(start),
    end: toISODate(end),
    progress: 0,
    dependencies: a.depends_on || [],
    phase_id: a.phase_id
  };
});
return [{ json: { ...$json, gantt: { project_start: toISODate(baseDate), tasks } } }];
